/* eslint-disable max-len */
import { Component, Event, EventEmitter, h, Host, Prop, State, Watch } from '@stencil/core';
import { isNullOrUndefinedOrEmptyString } from '@src/utils/mx-utils/utils';

import { IMenuData, IMenuItem, ISubMenu, ISubMenuItem } from './mx-nav.model';

@Component({
  tag: 'mx-nav',
  styleUrl: 'mx-nav.css'
})
export class MxNav {
  /** Used to hold the information about the selected menu item. */
  @Prop() readonly menuData: IMenuData[] = [];

  @Watch('menuData')
  onMenuDataChange(newValue: IMenuData[]) {
    const enrichData = this._enrichData(newValue);
    this._menuData = this._levelOrder(enrichData);
  }

  /** This is used to store the number of menu items. */
  @Prop() readonly columns = 2;
  /** Sets the navigation title. */
  @Prop() readonly navTitle = '';

  /** This event is emitted in case the user clicks on the Logo. */
  @Event() logoClick: EventEmitter;
  /** This event is emitted in case the user clicks on the Title. */
  @Event() titleClick: EventEmitter;
  /** This event is emitted in case the user clicks on the menu and you can use this to trigger your routing. */
  @Event() menuItemClick: EventEmitter;

  @State() _menuData: IMenuItem[] = [];

  componentWillLoad() {
    const enrichData = this._enrichData(this.menuData);
    this._menuData = this._levelOrder(enrichData);
  }

  /** convert IMenuData to IMenuItem interface **/
  private readonly _enrichData = (menuData): IMenuItem[] => {
    const menuItem: IMenuItem[] = [];
    for (let i = 0; i < menuData.length; i++) {
      const menuData1: IMenuData = menuData[i];
      menuItem.push({
        label: menuData1.label,
        link: menuData1.link,
        shouldHide: menuData1.shouldHide,
        children: []
      });

      if (menuData1.subMenu != null) {
        for (let j = 0; j < menuData1.subMenu.length; j++) {
          const subMenu: ISubMenu = menuData1.subMenu[j];
          menuItem[i].children.push({
            label: subMenu.label,
            link: subMenu.link,
            shouldHide: subMenu.shouldHide,
            children: []
          });

          if (subMenu.subMenuItems != null) {
            for (let k = 0; k < subMenu.subMenuItems.length; k++) {
              const subMenuItem: ISubMenuItem = subMenu.subMenuItems[k];
              menuItem[i].children[j].children.push({
                label: subMenuItem.label,
                link: subMenuItem.link,
                shouldHide: subMenuItem.shouldHide
              });

            }
          }
        }
      }
    }
    return menuItem;
  };

  /** recursive call to child node **/
  private readonly _levelOrder = (menuData: IMenuItem[]) => {
    return menuData.map((item) => {
      if (!Array.isArray(item.children) || item.children.length < 1) { // check if item is array
        const shouldHide: boolean = item.shouldHide || item.link == null;
        return shouldHide ? undefined : {
          ...item,
          shouldHide
        };
      } else {
        const shouldHide: boolean = item.shouldHide || this._shouldHide(item.children);

        return shouldHide ? undefined : {
          ...item,
          shouldHide,
          children: this._levelOrder(item.children)
        };
      }
    }).filter((element) => element !== undefined);
  };

  /** check if all below child is valid with link and should hide **/
  private readonly _shouldHide = (menuData: IMenuItem[]): boolean => {
    return menuData.map((item) => {
      if (!Array.isArray(item.children) || item.children.length < 1) {
        return item.shouldHide || item.link == null;
      } else {
        return item.shouldHide || this._shouldHide(item.children);
      }
    }).every(Boolean);  // shorthand for (item)=> item == true
  };

  private readonly handleMenuItemClick = (event: CustomEvent) => {
    this.menuItemClick.emit(event.detail);
  };

  private readonly handleTitleClick = () => {
    this.titleClick.emit();
  };

  private readonly handleLogoClick = () => {
    this.logoClick.emit();
  };

  render() {
    return (
      <Host>
        <div class='shadow-2'>
          <div class='bg-brand-800 w-full justify-between flex items-center h-48'>

            {/* Left Panel */}
            <div class='mx-header ml-16 h-48 items-center flex'>

              {/* Logo */}
              <a class='mx-logo' onClick={this.handleLogoClick}>
                <slot name='logo'>
                  <img
                    class='h-32'
                    src='data:image/svg+xml;base64,'
                    alt='The Kroger logo'></img>
                </slot>
              </a>

              {/* Title */}
              {!isNullOrUndefinedOrEmptyString(this.navTitle) && (
                <kds-link
                  linkClass='no-underline'
                  onClick={this.handleTitleClick}
                  inverse
                  implied
                  class='kds-Heading ml-16 mt-8 mx-header-title'>
                  {this.navTitle}
                </kds-link>
              )}

              {/* Menu */}
              <div class='flex items-center self-stretch'>
                <mx-header-nav
                  onHeaderMenuItemClick={this.handleMenuItemClick}
                  columns={this.columns}
                  data={this._menuData}></mx-header-nav>
              </div>
            </div>

            {/* Right Panel */}
            <div class='mx-helper'>
              <slot name='right-menu'></slot>
            </div>

          </div>
        </div>
      </Host>
    );
  }
}
